css:
/* --- 1. Hero --- */
.hero { background: linear-gradient(135deg, #fff7ed 0%, #fef3c7 50%, #ecfdf5 100%); padding: 80px 40px 60px; text-align: center; border-radius: 0 0 16px 16px; margin-bottom: 40px; }
.hero-badge { display: inline-block; background: #f97316; color: #fff; font-size: 0.85rem; font-weight: 700; padding: 4px 14px; border-radius: 50px; margin-bottom: 20px; letter-spacing: 0.06em; }
.hero .message { font-size: clamp(1.8rem, 5vw, 3rem); font-weight: 800; line-height: 1.3; color: #1e293b; margin-bottom: 16px; margin-top: 0; }
.hero-subtitle { font-size: 1.05rem; color: #475569; max-width: 480px; margin: 0 auto; line-height: 1.6; }

/* --- 2. Common --- */
section { max-width: 900px; margin: 0 auto 60px; padding: 0 20px; box-sizing: border-box; }
section h2 { font-size: 1.6rem; border-left: 6px solid #f97316; padding-left: 14px; margin-bottom: 24px; color: #1e293b; }

/* --- 3. Concept (PC) --- */
.concept ul { display: grid; grid-template-columns: repeat(2, 1fr); gap: 20px; list-style: none; padding: 0; }
.concept li { 
  background: #fff; padding: 20px; border-radius: 8px; border: 1px solid #d1d5db; 
  box-shadow: 0 8px 16px rgba(0,0,0,0.06); display: flex; align-items: flex-start;
  box-sizing: border-box;
}
.concept .icon { width: 50px; flex-shrink: 0; font-size: 2rem; }
.concept li strong { width: calc(45% - 50px); color: #ea580c; flex-shrink: 0; margin-right: 15px; font-weight: 700; word-wrap: break-word; }
.concept li span, .concept li p { width: 55%; color: #475569; font-size: 0.9rem; margin: 0; }

/* --- 4. Planning & Style (PC) --- */
.planning .cols, .style .cols { display: grid; gap: 20px; width: 100%; }
.planning .cols { grid-template-columns: repeat(3, 1fr); }
.style .cols { grid-template-columns: repeat(3, 1fr); }

.planning .col, .style .col { 
  background: #fff; padding: 24px; border-radius: 8px; border: 1px solid #d1d5db; 
  box-shadow: 0 8px 16px rgba(0,0,0,0.06); 
}
.planning h3 { font-size: 1.15rem; color: #1e293b; margin: 0 0 12px; }
.planning h3 span.pic { display: block; margin: 0 0 12px 0; text-align: center; }
.planning h3 img { width: 100%; max-width: 265px; height: auto; border-radius: 12px; }

/* --- 5. Usage & Download --- */
.usage { text-align: center; margin: 40px auto; background: #fff; padding: 24px; border-radius: 12px; border: 2px solid #fed7aa; color: #475569; font-weight: 600; }
.dl-section { background: linear-gradient(135deg, #fff7ed, #fef3c7); text-align: center; padding: 60px 20px; border-radius: 12px; }
.dl-section h2 { border: none !important; padding: 0 !important; font-size: 1.8rem; text-align: center; }
.dl-btn { display: inline-block; background: #f97316; color: #fff !important; font-size: 1.15rem; font-weight: 800; padding: 16px 44px; border-radius: 50px; text-decoration: none; box-shadow: 0 8px 24px rgba(249,115,22,0.3); margin-top: 24px; }

.final-image { text-align: center; padding: 60px 0; }
.final-image img { max-width: 100%; height: auto; border-radius: 16px; }


/* --- 6. Mobile (768px以下) --- */
@media (max-width: 768px) {
  section { margin-bottom: 30px !important; }
  
  /* Concept & Planning: カードを縦1列に並べる */
  .concept ul, .planning .cols { 
    display: flex !important;
    flex-direction: column !important;
    gap: 15px !important;
  }
  
  /* カードの中身をL字レイアウトにする */
  .concept li, .planning .col { 
    display: grid !important; 
    grid-template-columns: 80px 1fr !important; /* 左側に画像用の幅を確保 */
    grid-template-rows: auto auto !important; 
    gap: 2px 15px !important;
    padding: 16px !important;
    align-items: start;
  }  .concept ul { display: flex; flex-direction: column; gap: 12px; padding: 0; width: 100%; }
  .concept li { 
    display: grid !important; 
    grid-template-columns: 60px 1fr !important; 
    grid-template-rows: auto auto !important;
    gap: 2px 10px !important;
    align-items: center;
    width: 100% !important;
    box-sizing: border-box;
  }
  
  .concept .icon { 
    grid-column: 1 !important; 
    grid-row: 1 / 3 !important; 
    width: 100% !important;
    text-align: center;
    font-size: 2.5rem;
    margin: 0;
  }
  
  .concept li strong { 
    grid-column: 2 !important; 
    grid-row: 1 !important; 
    width: 100% !important;
    margin: 0;
    font-size: 1rem;
    align-self: end;
  }
  
  .concept li span, .concept li p { 
    grid-column: 2 !important; 
    grid-row: 2 !important; 
    width: 100% !important;
    margin: 0;
    font-size: 0.85rem;
    align-self: start;
  }
  
  /* Planningの要素配置をバラしてGridにはめ込む */
  .planning h3 { display: contents !important; } /* h3の枠を無視して中身をGridへ */
  .planning .pic { 
    grid-column: 1 !important; 
    grid-row: 1 / 3 !important; 
    margin: 0 !important; 
  }
  .planning .pic img { 
    width: 80px !important; 
    height: 80px !important; 
    object-fit: cover; 
    border-radius: 8px; 
  }
  
  /* タイトルテキスト (h3の中の文字) */
  .planning .col h3 { 
    grid-column: 2 !important; 
    grid-row: 1 !important; 
    font-size: 1.05rem !important; 
    margin: 0 !important; 
    align-self: end; 
    font-weight: 800;
  }
  
  /* 説明文 (p) */
  .planning .col p { 
    grid-column: 2 !important; 
    grid-row: 2 !important; 
    margin: 0 !important; 
    font-size: 0.88rem !important; 
    align-self: start; 
    line-height: 1.5; 
    color: #475569;
  }

  /* Style & Other sections */
  .style .cols { grid-template-columns: 1fr !important; }
}
